import { Component as ReactComponent } from '@wordpress/element';
import { __ } from "@wordpress/i18n";

export class LicenseTooltip extends ReactComponent {
    render() {
        const { payload } = this.props;
        const orderData = payload[0]?.payload || {};

        // Handle case where payload might be empty or undefined
        if (!orderData) {
            return null;
        }
        //console.log(orderData);
        return (
            <div className="d3-chart__container">
                <div className="d3-chart__tooltip">
                    <h4>{this.props.dateRange}</h4>
                    <ul>
                        <li className="key-row">
                            <div className="key-container">
                                <span className="key-color" style={{ backgroundColor: '#2271b1' }} />
                                <span className="key-key">{__("#OrderID", "license-manager-for-woocommerce")}</span>
                            </div>
                            <span className="key-value">{orderData.order_id}</span>
                        </li>

                        {/* Render line items dynamically */}
                        {orderData.line_items_data && orderData.line_items_data.length > 0 ? (
                            orderData.line_items_data.map((line_items_value, index) => (
                                <li className="key-row" key={index}>
                                    <div className="key-container">
                                        <span className="key-color" style={{ backgroundColor: '#f0a' }} />
                                        <span className="key-key">{line_items_value}</span>
                                    </div>
                                </li>
                            ))
                        ) : null}

                        <li className="key-row">
                            <div className="key-container">
                                <span className="key-color" style={{ backgroundColor: '#8884d8' }} />
                                <span className="key-key">{__("#Products Total", "license-manager-for-woocommerce")}</span>
                            </div>
                            <span className="key-value">{this.props.currency.render(orderData.totalAmount)}</span>
                        </li>
                    </ul>
                </div>
            </div>
        );
    }
}
