import {addFilter} from '@wordpress/hooks';
import {__} from '@wordpress/i18n';
import {Licenses} from "./analytics/Licenses";

addFilter('woocommerce_admin_reports_list', 'licenses', (reports) => {
    return [
        ...reports,
        {
            report: 'licenses',
            title: __('Licenses', 'license-manager-for-woocommerce'),
            component: Licenses
        },
    ];
});
