import { Component as ReactComponent, Fragment } from "@wordpress/element";
import { __ } from "@wordpress/i18n";
import { appendTimestamp, getCurrentDates, getDateParamsFromQuery, isoDateFormat } from "@woocommerce/date";
import apiFetch from "@wordpress/api-fetch";
import {
    ChartPlaceholder,
    ReportFilters,
    SummaryList,
    SummaryListPlaceholder,
    SummaryNumber,
    TablePlaceholder,
} from "@woocommerce/components";
import Currency from "@woocommerce/currency";
import { CURRENCY as storeCurrencySetting } from "@woocommerce/settings";
import { LicenseChart } from "./LicenseChart";
import { LicenseTable } from "./LicenseTable";

export class Licenses extends ReactComponent {
    constructor(props) {
        super(props);

        this.state = {
            dateQuery: this.createDateQuery(props.query),
            currency: new Currency(storeCurrencySetting),
            totalAppCount: [],
            allLicenses: [],
            orders: [],
            data: { loading: true },
        };

        this.handleDateChange = this.handleDateChange.bind(this);
        this._isMounted = false; // Flag to track mounting status
    }

    componentDidMount() {
        this._isMounted = true;
        this.fetchData(this.state.dateQuery);
    }

    componentWillUnmount() {
        this._isMounted = false;
    }

    createDateQuery(query) {
        const { period, compare, before, after } = getDateParamsFromQuery(query);
        const { primary: primaryDate, secondary: secondaryDate } = getCurrentDates(query);
        return { period, compare, before, after, primaryDate, secondaryDate };
    }

    getQueryParameters(dateQuery) {
       // console.log(dateQuery);
        const afterDate = encodeURIComponent(appendTimestamp(dateQuery.primaryDate.after, "start"));
        const beforeDate = encodeURIComponent(appendTimestamp(dateQuery.primaryDate.before, "end"));
        const interval = encodeURIComponent(dateQuery?.period || "today");
        return `&after=${afterDate}&before=${beforeDate}&interval=${interval}&order=asc`;
    }

    fetchData(dateQuery) {
        if (!this.state.data.loading) {
            this.setState({ data: { loading: true } });
        }

        const queryParameters = this.getQueryParameters(dateQuery);
        const licensesPath = `/wc-analytic-data/reports/licenses?${queryParameters}`;
        const ordersPath = `/wc-analytics/orders?_fields${queryParameters}`;

        Promise.all([
            this.state.allLicenses.length === 0 ? apiFetch({ path: licensesPath }) : Promise.resolve(this.state.allLicenses),
            apiFetch({ path: ordersPath }),
        ])
            .then(([licenses, orders]) => {
                if (this._isMounted) { // Check if component is still mounted
                    this.setState({
                        totalAppCount: licenses,
                        orders,
                        data: { loading: false },
                    });
                }
               // console.log(licensesPath);
               // console.log(licenses);
            })
            .catch((err) => console.error("Error fetching data:", err));
    }

    handleDateChange(newQuery) {
        const newDateQuery = this.createDateQuery(newQuery);
        this.setState({ dateQuery: newDateQuery });
        this.fetchData(newDateQuery);
    }

    render() {
        const { dateQuery, currency, totalAppCount, orders, data } = this.state;

        const reportFilters = (
            <ReportFilters
                dateQuery={dateQuery}
                query={this.props.query}
                path={this.props.path}
                currency={currency}
                isoDateFormat={isoDateFormat}
                onDateSelect={this.handleDateChange}
            />
        );

        const tableHeaders = [
            { key: "product", label: __("Product", "license-manager-for-woocommerce"), isLeftAligned: true, isSortable: true, required: true },
            { key: "license_sold", label: __("Licenses Sold", "license-manager-for-woocommerce"), isSortable: true, isNumeric: true },
            { key: "activations", label: __("Activations", "license-manager-for-woocommerce"), isSortable: true, isNumeric: true },
            { key: "net_sales", label: __("Net Sales", "license-manager-for-woocommerce"), isSortable: true, isNumeric: true },
        ];

        if (data.loading) {
            return (
                <Fragment>
                   
                    <div id="license-manager-for-woocommerce">
                        {reportFilters}
                        <div className="woocommerce-placeholder-shimmer">
                            <SummaryListPlaceholder numberOfItems={8} />
                        </div>
                        <div className="woocommerce-placeholder-shimmer">
                            <ChartPlaceholder height={300} />
                        </div>
                        <div className="woocommerce-placeholder-shimmer">
                            <TablePlaceholder
                                caption={__("Top Licenses", "license-manager-for-woocommerce")}
                                headers={tableHeaders}
                            />
                        </div>
                   </div>      
                </Fragment>
            );
        } 
        const total_order_count = totalAppCount.sales_license_by_products.reduce((sum, item) => sum + parseFloat(item.total_order), 0);
        console.log(totalAppCount);
        return (
            <Fragment>
                <div id="license-manager-for-woocommerce">
                    {reportFilters}
                    <SummaryList>
                        {() => [
                            <SummaryNumber key="total_applications" value={totalAppCount.total_application_sold} label={__("Total Applications", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="total_licenses" value={totalAppCount.total_licenses_sold} label={__("Total Licenses Sold", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="total_expired_licenses" value={totalAppCount.total_expired_licenses} label={__("Total Expired Licenses", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="total_generators" value={totalAppCount.total_generators_assigned} label={__("Total Generators Assigned", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="total_orders" value={total_order_count} label={__("Total Orders", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="total_activations" value={totalAppCount.total_activations} label={__("Total Activations", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="all_licenses" value={totalAppCount.all_licenses} label={__("Total Licenses", "license-manager-for-woocommerce")} />,
                            <SummaryNumber key="total_certificates" value={totalAppCount.total_certificates_downloaded} label={__("Total Certificates Downloaded (All Time)", "license-manager-for-woocommerce")} />,
                      ]}
                    </SummaryList>
                </div>
                <LicenseChart
                    chartData={orders}
                    dateRange={dateQuery.primaryDate.range}
                    currency={currency}
                />
                <LicenseTable total_order_count={total_order_count}
                    licenseData={totalAppCount.sales_license_by_products}
                    totals={totalAppCount.total_orders}
                    currency={currency}
                    headers={tableHeaders}
                />
            </Fragment>
        );
    }
}
