import { __ } from "@wordpress/i18n";
import { useMemo } from "react";
import {
    Bar,
    BarChart,
    CartesianGrid,
    ResponsiveContainer,
    Tooltip,
    XAxis,
    YAxis,
} from "recharts";
import { LicenseTooltip } from "./LicenseTooltip";

export const LicenseChart = ({ chartData = [], dateRange, currency }) => {

   // console.log(chartData);
    const allProductsHaveLmfwcOrderComplete = (order) => {
        return (order.line_items || []).some(item => 
            item["lmfwc_licensed_product"] &&
            item["lmfwc_licensed_product"].trim() !== ""
        );
    };
  
    const processedChartData = useMemo(() => {
     
        const groupedData = chartData.reduce((acc, order) => {
            let totalAmount = 0;
            let totalQuantity = 0;
            let line_items_data = []; // Initialize the array for product names
           
        if (allProductsHaveLmfwcOrderComplete(order)) {

                    (order.line_items || []).forEach(item => {

                        if (item["lmfwc_licensed_product"] &&
                            item["lmfwc_licensed_product"].trim() !== "") {
                            totalAmount += parseFloat(item.total || 0);
                            totalQuantity += item.quantity || 0;
                            line_items_data.push(item.name); 
                            
                        }
                    });

                    // Use the order ID as the key and store the aggregated data
                    if (acc[order.id]) {
                        acc[order.id].order_id = order.id ;
                        acc[order.id].totalAmount += totalAmount;
                        acc[order.id].totalQuantity += totalQuantity;
     
                        acc[order.id].line_items_data = [...acc[order.id].line_items_data, ...line_items_data]; // Combine previous data with current one
                    } else {
                        acc[order.id] = {
                            order_id: order.id,
                            label: new Date(order.date_created).toLocaleDateString("en-US"), // Display the order date on the X-Axis
                            totalAmount,
                            totalQuantity,
                            line_items_data,
 
                        };
                    }

        }


            return acc;
        }, {});

        // Convert the grouped object back to an array format for recharts
        return Object.values(groupedData);
    }, [chartData]);

    //console.log(processedChartData);

    const isChartEmpty = !processedChartData || processedChartData.length === 0;

    return (
        <div className="licensechart-chart">
            <div className="licensechart-chart__header">
                <h2 className="licensechart-chart__title">
                    {__("Sales by license", "license-manager-for-woocommerce")}
                </h2>
            </div>
            <div className="licensechart-chart__body licensechart-chart__body-column">
                <div className="d3-chart__container">
                    <ResponsiveContainer width="100%" height={300} aria-label="License sales bar chart">
                        {isChartEmpty ? (
                            <div className="d3-chart__empty-message">
                                {__("No data for the selected date range", "license-manager-for-woocommerce")}
                            </div>
                        ) : (
                            <BarChart data={processedChartData}>
                                <CartesianGrid vertical={false} />
                                <Bar dataKey="totalAmount" fill="#8884d8" />
                                <XAxis dataKey="label" />
                                <YAxis domain={[0, dataMax => Math.max(100, Math.ceil(dataMax * 1.05))]} />
                                <Tooltip
                                   wrapperStyle={{ pointerEvents: "auto" }}
                                    cursor={{ fill: "rgba(0, 0, 0, 0.1)" }}
                                    content={({ active, payload }) =>
                                        active && payload && payload.length ? (
                                            <LicenseTooltip
                                                payload={payload}
                                                dateRange={dateRange}
                                                currency={currency}
                                            />
                                        ) : null
                                    }
                                />
                            </BarChart>
                        )}
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};
