import { __ } from "@wordpress/i18n";
import { Component as ReactComponent } from "@wordpress/element";
import { TableCard } from "@woocommerce/components";

export class LicenseTable extends ReactComponent {
    constructor(props) {
        super(props);

        const defaultSortColumn = "sales";
        const defaultSortOrder = "desc";

        this.state = {
            licenseData: this.sortData(props.licenseData, defaultSortColumn, defaultSortOrder),
            sortColumn: defaultSortColumn,
            sortOrder: defaultSortOrder,
        };
        
    }

    // Utility to toggle sort order
    toggleSortOrder = (currentOrder) => (currentOrder === "asc" ? "desc" : "asc");

    // Apply sorting to header options
    configureHeaderSorting = (header) => ({
        ...header,
        defaultSort: header.key === this.state.sortColumn,
        defaultOrder: header.key === this.state.sortColumn ? this.state.sortOrder : undefined,
    });

    // Sort data by column and order
    sortData = (data, column, order) => {
        const sortFactor = order === "asc" ? 1 : -1;
        return [...data].sort((a, b) => {
            if (a[column] > b[column]) return sortFactor;
            if (a[column] < b[column]) return -sortFactor;
            return 0;
        });
    };

    // Handle sorting logic
    handleSort = (newSortColumn) => {
        this.setState((prevState) => {
            const { sortColumn, sortOrder, licenseData } = prevState;
            const newSortOrder = sortColumn === newSortColumn ? this.toggleSortOrder(sortOrder) : "desc";
            const sortedData = this.sortData(licenseData, newSortColumn, newSortOrder);

            return {
                sortColumn: newSortColumn,
                sortOrder: newSortOrder,
                licenseData: sortedData,
            };
        });
    };

    render() {
        const { licenseData, sortColumn, sortOrder } = this.state;
        const { headers, totals, currency , total_order_count} = this.props;
        const totalOrderSum = licenseData.reduce((sum, item) => sum + parseFloat(item.total_order_sum), 0);
        const totalLicenses = licenseData.reduce((sum, item) => sum + parseFloat(item.total_licenses), 0);

        const tableData = {
            headers: headers.map(this.configureHeaderSorting),
            rows: licenseData.map((item) => [
                { display: item.post_title, value: item.post_title },
                { display: item.total_licenses, value: item.total_licenses },
                { display: item.times_activated ?? "0", value: item.times_activated ?? "0" },
                { display: currency.render(item.total_order_sum), value: item.total_order_sum },
            ]),
            summary: [
                {
                    key: "total_sales",
                    label: __("Sales in this period", "wc-admin-sales-by-license"),
                    value: currency.render(totalOrderSum.toFixed(2)),
                },
                {
                    key: "total_orders",
                    label: __("Orders in this period", "wc-admin-sales-by-license"),
                    value: total_order_count,
                },
                {
                    key: "total_licenses",
                    label: __("Licenses in this period", "wc-admin-sales-by-license"),
                    value: totalLicenses,
                },
            ],
        };

        return (
            <TableCard
                className="table_top_licenses"
                title={__("Top products sales", "wc-admin-sales-by-license")}
                rows={tableData.rows}
                headers={tableData.headers}
                rowsPerPage={100}
                totalRows={tableData.rows.length}
                summary={tableData.summary}
                onSort={this.handleSort}
            />
        );
    }
}

// Default props for demonstration
LicenseTable.defaultProps = {
    headers: [
        { label: __("Product Name", "wc-admin-sales-by-license"), key: "post_title", isSortable: true },
        { label: __("Licenses", "wc-admin-sales-by-license"), key: "total_licenses", isSortable: true },
        { label: __("Activations", "wc-admin-sales-by-license"), key: "times_activated", isSortable: true },
        { label: __("Price", "wc-admin-sales-by-license"), key: "total_order_sum", isSortable: true },
    ],
    licenseData: [
        { post_title: "Product A", total_licenses: 10, times_activated: 8, total_order_sum: 50 },
        { post_title: "Product B", total_licenses: 5, times_activated: 3, total_order_sum: 30 },
        { post_title: "Product C", total_licenses: 20, times_activated: 15, total_order_sum: 100 },
        { post_title: "Product D", total_licenses: 8, times_activated: 6, total_order_sum: 40 },
    ],
    totals: {
        total_sales: 220,
        total_orders: 15,
        total_licenses: 43,
    },
    currency: {
        render: (value) => `$${value.toFixed(2)}`,
    },
};
